class ModelDownloader:
    """Downloads pretrained model checkpoints from public repositories."""

    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self._download_manifest = self.cache_dir / "manifest.json"
        self._manifest = self._load_manifest()

    def _load_manifest(self) -> Dict:
        if self._download_manifest.exists():
            with open(self._download_manifest, "r") as f:
                return json.load(f)
        return {}

    def _save_manifest(self):
        with open(self._download_manifest, "w") as f:
            json.dump(self._manifest, f, indent=2)

    def _compute_file_hash(self, filepath: Path) -> str:
        sha256 = hashlib.sha256()
        with open(filepath, "rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                sha256.update(chunk)
        return sha256.hexdigest()

    def download_checkpoint(
        self,
        model_name: str,
        url: Optional[str] = None,
        force: bool = False
    ) -> Path:
        """Download a model checkpoint from URL."""
        if model_name in MODEL_REGISTRY and url is None:
            config = MODEL_REGISTRY[model_name]
            url = config.url
        elif url is None:
            raise ValueError(
                f"Model '{model_name}' not in registry. Provide a URL."
            )

        filename = f"{model_name}_{url.split('/')[-1]}"
        filepath = self.cache_dir / filename

        if filepath.exists() and not force:
            if model_name in self._manifest:
                logger.info(f"Model '{model_name}' found in cache: {filepath}")
                return filepath

        logger.info(f"Downloading model '{model_name}' from {url}")

        try:
            checkpoint_path = torch.hub.download_url_to_file(
                url,
                str(filepath),
                progress=True
            )
            file_hash = self._compute_file_hash(filepath)
            self._manifest[model_name] = {
                "url": url,
                "filepath": str(filepath),
                "hash": file_hash,
            }
            self._save_manifest()

            logger.info(f"Successfully downloaded '{model_name}' to {filepath}")
            return filepath

        except Exception as e:
            logger.error(f"Failed to download model '{model_name}': {e}")
            if filepath.exists():
                filepath.unlink()
            raise

    def list_cached_models(self) -> List[str]:
        """List all cached models."""
        return list(self._manifest.keys())

    def clear_cache(self, model_name: Optional[str] = None):
        """Clear cached models."""
        if model_name:
            if model_name in self._manifest:
                filepath = Path(self._manifest[model_name]["filepath"])
                if filepath.exists():
                    filepath.unlink()
                del self._manifest[model_name]
                self._save_manifest()
                logger.info(f"Cleared cache for '{model_name}'")
        else:
            for name, info in self._manifest.items():
                filepath = Path(info["filepath"])
                if filepath.exists():
                    filepath.unlink()
            self._manifest = {}
            self._save_manifest()
            logger.info("Cleared all model cache")


