class ModelLoader:
    """Loads pretrained model checkpoints and prepares them for fine-tuning."""

    ARCHITECTURE_MAP = {
        "resnet18": models.resnet18,
        "resnet50": models.resnet50,
        "resnet101": models.resnet101,
        "vgg16": models.vgg16,
        "densenet121": models.densenet121,
        "mobilenet_v2": models.mobilenet_v2,
        "efficientnet_b0": models.efficientnet_b0,
    }

    def __init__(self, device: Optional[torch.device] = None):
        if device is None:
            self.device = torch.device(
                "cuda" if torch.cuda.is_available() else "cpu"
            )
        else:
            self.device = device

    def create_architecture(self, architecture: str) -> nn.Module:
        """Create a model architecture without pretrained weights."""
        if architecture not in self.ARCHITECTURE_MAP:
            raise ValueError(
                f"Unknown architecture '{architecture}'. "
                f"Available: {list(self.ARCHITECTURE_MAP.keys())}"
            )
        model = self.ARCHITECTURE_MAP[architecture](weights=None)
        return model

    def load_checkpoint(
        self,
        checkpoint_path: str,
        architecture: str,
        strict: bool = False
    ) -> nn.Module:
        """Load a checkpoint into a model architecture."""
        model = self.create_architecture(architecture)
        logger.info(f"Loading checkpoint from {checkpoint_path}")

        checkpoint = torch.load(
            checkpoint_path,
            map_location=self.device,
            weights_only=False
        )

        if isinstance(checkpoint, dict):
            if "state_dict" in checkpoint:
                state_dict = checkpoint["state_dict"]
            elif "model_state_dict" in checkpoint:
                state_dict = checkpoint["model_state_dict"]
            elif "model" in checkpoint:
                state_dict = checkpoint["model"]
            else:
                state_dict = checkpoint
        else:
            state_dict = checkpoint

        # Handle DataParallel wrapped models
        cleaned_state_dict = {}
        for key, value in state_dict.items():
            new_key = key.replace("module.", "")
            cleaned_state_dict[new_key] = value

        try:
            model.load_state_dict(cleaned_state_dict, strict=strict)
            logger.info("Checkpoint loaded successfully (strict=%s)", strict)
        except RuntimeError as e:
            logger.warning(f"Strict loading failed: {e}")
            logger.info("Attempting partial loading...")
            model_dict = model.state_dict()
            compatible = {
                k: v for k, v in cleaned_state_dict.items()
                if k in model_dict and v.shape == model_dict[k].shape
            }
            model_dict.update(compatible)
            model.load_state_dict(model_dict)
            logger.info(
                f"Loaded {len(compatible)}/{len(model_dict)} layers"
            )

        return model

    def load_from_torchvision(
        self,
        architecture: str,
        pretrained: bool = True
    ) -> nn.Module:
        """Load a pretrained model directly from torchvision."""
        if architecture not in self.ARCHITECTURE_MAP:
            raise ValueError(f"Unknown architecture '{architecture}'")

        if pretrained:
            weights_enum = {
                "resnet18": models.ResNet18_Weights.DEFAULT,
                "resnet50": models.ResNet50_Weights.DEFAULT,
                "resnet101": models.ResNet101_Weights.DEFAULT,
                "vgg16": models.VGG16_Weights.DEFAULT,
                "densenet121": models.DenseNet121_Weights.DEFAULT,
                "mobilenet_v2": models.MobileNet_V2_Weights.DEFAULT,
                "efficientnet_b0": models.EfficientNet_B0_Weights.DEFAULT,
            }
            weights = weights_enum.get(architecture)
            model = self.ARCHITECTURE_MAP[architecture](weights=weights)
            logger.info(
                f"Loaded pretrained '{architecture}' from torchvision"
            )
        else:
            model = self.ARCHITECTURE_MAP[architecture](weights=None)
            logger.info(f"Created '{architecture}' without pretrained weights")

        return model

    def adapt_classifier(
        self,
        model: nn.Module,
        architecture: str,
        num_classes: int,
        dropout: float = 0.5
    ) -> nn.Module:
        """Replace the final classifier layer for a new number of classes."""
        if architecture in ["resnet18", "resnet50", "resnet101"]:
            in_features = model.fc.in_features
            model.fc = nn.Sequential(
                nn.Dropout(dropout),
                nn.Linear(in_features, 512),
                nn.ReLU(inplace=True),
                nn.Dropout(dropout * 0.5),
                nn.Linear(512, num_classes),
            )
            logger.info(
                f"Replaced ResNet classifier: {in_features} -> {num_classes}"
            )

        elif architecture == "vgg16":
            in_features = model.classifier[6].in_features
            model.classifier[6] = nn.Sequential(
                nn.Dropout(dropout),
                nn.Linear(in_features, num_classes),
            )
            logger.info(
                f"Replaced VGG classifier: {in_features} -> {num_classes}"
            )

        elif architecture == "densenet121":
            in_features = model.classifier.in_features
            model.classifier = nn.Sequential(
                nn.Dropout(dropout),
                nn.Linear(in_features, num_classes),
            )
            logger.info(
                f"Replaced DenseNet classifier: {in_features} -> {num_classes}"
            )

        elif architecture == "mobilenet_v2":
            in_features = model.classifier[1].in_features
            model.classifier[1] = nn.Sequential(
                nn.Dropout(dropout),
                nn.Linear(in_features, num_classes),
            )
            logger.info(
                f"Replaced MobileNet classifier: {in_features} -> {num_classes}"
            )

        elif architecture == "efficientnet_b0":
            in_features = model.classifier[1].in_features
            model.classifier[1] = nn.Sequential(
                nn.Dropout(dropout),
                nn.Linear(in_features, num_classes),
            )
            logger.info(
                f"Replaced EfficientNet classifier: {in_features} -> {num_classes}"
            )

        else:
            raise ValueError(
                f"Classifier adaptation not implemented for '{architecture}'"
            )

        return model


