class CustomImageDataset(Dataset):
    """Custom dataset that loads images from a directory structure.

    Expected structure:
        root/
            class1/
                img1.jpg
                img2.jpg
            class2/
                img3.jpg
                ...
    """

    def __init__(
        self,
        root_dir: str,
        transform: Optional[transforms.Compose] = None,
    ):
        self.root_dir = Path(root_dir)
        self.transform = transform
        self.samples = []
        self.class_to_idx = {}
        self.classes = []

        if self.root_dir.exists():
            self._load_from_directory()
        else:
            logger.warning(
                f"Dataset directory {root_dir} does not exist. "
                "Using synthetic data for demonstration."
            )

    def _load_from_directory(self):
        """Load samples from directory structure."""
        classes = sorted([
            d.name for d in self.root_dir.iterdir() if d.is_dir()
        ])
        self.classes = classes
        self.class_to_idx = {cls: idx for idx, cls in enumerate(classes)}

        for cls in classes:
            cls_dir = self.root_dir / cls
            for img_path in cls_dir.iterdir():
                if img_path.suffix.lower() in [
                    '.jpg', '.jpeg', '.png', '.bmp', '.tiff'
                ]:
                    self.samples.append((str(img_path), self.class_to_idx[cls]))

        logger.info(
            f"Loaded {len(self.samples)} samples from {len(classes)} classes"
        )

    def __len__(self):
        return len(self.samples)

    def __getitem__(self, idx):
        if len(self.samples) > 0:
            img_path, label = self.samples[idx]
            from PIL import Image
            image = Image.open(img_path).convert("RGB")
            if self.transform:
                image = self.transform(image)
            return image, label
        return torch.randn(3, 224, 224), 0


class SyntheticDataset(Dataset):
    """Synthetic dataset for testing the pipeline."""

    def __init__(
        self,
        num_samples: int = 1000,
        num_classes: int = 10,
        image_size: int = 224,
    ):
        self.num_samples = num_samples
        self.num_classes = num_classes
        self.image_size = image_size
        self.classes = [f"class_{i}" for i in range(num_classes)]

    def __len__(self):
        return self.num_samples

    def __getitem__(self, idx):
        image = torch.randn(3, self.image_size, self.image_size)
        label = idx % self.num_classes
        return image, label


# ============================================================
# Data Transforms
# ============================================================

def get_transforms(
    input_size: int = 224,
    is_training: bool = True
) -> transforms.Compose:
    """Get data transforms for training or validation."""
    if is_training:
        return transforms.Compose([
            transforms.RandomResizedCrop(input_size),
            transforms.RandomHorizontalFlip(),
            transforms.RandomVerticalFlip(p=0.1),
            transforms.ColorJitter(
                brightness=0.2, contrast=0.2, saturation=0.2, hue=0.1
            ),
            transforms.RandomRotation(15),
            transforms.ToTensor(),
            transforms.Normalize(
                mean=[0.485, 0.456, 0.406],
                std=[0.229, 0.224, 0.225]
            ),
        ])
    else:
        return transforms.Compose([
            transforms.Resize(int(input_size * 1.14)),
            transforms.CenterCrop(input_size),
            transforms.ToTensor(),
            transforms.Normalize(
                mean=[0.485, 0.456, 0.406],
                std=[0.229, 0.224, 0.225]
            ),
        ])


