class FineTuner:
    """Fine-tunes pretrained models on custom datasets."""

    def __init__(
        self,
        model: nn.Module,
        config: TrainingConfig,
        architecture: str = "resnet50",
    ):
        self.config = config
        self.architecture = architecture

        if config.device == "auto":
            self.device = torch.device(
                "cuda" if torch.cuda.is_available() else "cpu"
            )
        else:
            self.device = torch.device(config.device)

        self.model = model.to(self.device)

        os.makedirs(config.checkpoint_dir, exist_ok=True)

        self.best_val_acc = 0.0
        self.best_val_loss = float("inf")
        self.training_history = {
            "train_loss": [],
            "train_acc": [],
            "val_loss": [],
            "val_acc": [],
            "lr": [],
        }

    def freeze_backbone(self, unfreeze_last_n: int = 2):
        """Freeze all layers except the last N and the classifier."""
        all_params = list(self.model.named_parameters())

        # First freeze everything
        for name, param in all_params:
            param.requires_grad = False

        # Unfreeze classifier layers
        classifier_keywords = ["fc", "classifier", "head"]
        for name, param in all_params:
            if any(kw in name for kw in classifier_keywords):
                param.requires_grad = True

        # Unfreeze last N layers/blocks
        if unfreeze_last_n > 0:
            if self.architecture in ["resnet18", "resnet50", "resnet101"]:
                layers = ["layer4", "layer3", "layer2", "layer1"]
                for layer_name in layers[:unfreeze_last_n]:
                    for name, param in all_params:
                        if layer_name in name:
                            param.requires_grad = True

            elif self.architecture == "vgg16":
                # Unfreeze last feature blocks
                feature_params = [
                    (name, param) for name, param in all_params
                    if "features" in name
                ]
                n_unfreeze = min(
                    unfreeze_last_n * 4, len(feature_params)
                )
                for name, param in feature_params[-n_unfreeze:]:
                    param.requires_grad = True

            elif self.architecture == "densenet121":
                blocks = ["denseblock4", "denseblock3", "denseblock2"]
                for block_name in blocks[:unfreeze_last_n]:
                    for name, param in all_params:
                        if block_name in name:
                            param.requires_grad = True

            else:
                # Generic: unfreeze last N% of parameters
                total = len(all_params)
                n_unfreeze = max(1, total * unfreeze_last_n // 10)
                for name, param in all_params[-n_unfreeze:]:
                    param.requires_grad = True

        trainable = sum(
            p.numel() for p in self.model.parameters() if p.requires_grad
        )
        total = sum(p.numel() for p in self.model.parameters())
        logger.info(
            f"Trainable parameters: {trainable:,} / {total:,} "
            f"({100 * trainable / total:.1f}%)"
        )

    def get_optimizer_and_scheduler(self):
        """Create optimizer with differential learning rates and scheduler."""
        # Separate parameters into groups
        classifier_params = []
        backbone_params = []
        classifier_keywords = ["fc", "classifier", "head"]

        for name, param in self.model.named_parameters():
            if not param.requires_grad:
                continue
            if any(kw in name for kw in classifier_keywords):
                classifier_params.append(param)
            else:
                backbone_params.append(param)

        param_groups = [
            {
                "params": backbone_params,
                "lr": self.config.learning_rate * 0.1,
            },
            {
                "params": classifier_params,
                "lr": self.config.learning_rate,
            },
        ]

        optimizer = optim.SGD(
            param_groups,
            momentum=self.config.momentum,
            weight_decay=self.config.weight_decay,
        )

        scheduler = optim.lr_scheduler.StepLR(
            optimizer,
            step_size=self.config.lr_step_size,
            gamma=self.config.lr_gamma,
        )

        return optimizer, scheduler

    def train_epoch(
        self,
        train_loader: DataLoader,
        criterion: nn.Module,
        optimizer: optim.Optimizer,
    ) -> Tuple[float, float]:
        """Train for one epoch."""
        self.model.train()
        running_loss = 0.0
        correct = 0
        total = 0

        for batch_idx, (inputs, labels) in enumerate(train_loader):
            inputs = inputs.to(self.device)
            labels = labels.to(self.device)

            optimizer.zero_grad()
            outputs = self.model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()

            # Gradient clipping
            torch.nn.utils.clip_grad_norm_(
                self.model.parameters(), max_norm=1.0
            )

            optimizer.step()

            running_loss += loss.item() * inputs.size(0)
            _, predicted = outputs.max(1)
            total += labels.size(0)
            correct += predicted.eq(labels).sum().item()

            if (batch_idx + 1) % 50 == 0:
                logger.info(
                    f"  Batch [{batch_idx + 1}/{len(train_loader)}] "
                    f"Loss: {loss.item():.4f} "
                    f"Acc: {100.0 * correct / total:.2f}%"
                )

        epoch_loss = running_loss / total
        epoch_acc = 100.0 * correct / total
        return epoch_loss, epoch_acc

    @torch.no_grad()
    def validate(
        self,
        val_loader: DataLoader,
        criterion: nn.Module,
    ) -> Tuple[float, float]:
        """Validate the model."""
        self.model.eval()
        running_loss = 0.0
        correct = 0
        total = 0

        for inputs, labels in val_loader:
            inputs = inputs.to(self.device)
            labels = labels.to(self.device)

            outputs = self.model(inputs)
            loss = criterion(outputs, labels)

            running_loss += loss.item() * inputs.size(0)
            _, predicted = outputs.max(1)
            total += labels.size(0)
            correct += predicted.eq(labels).sum().item()

        epoch_loss = running_loss / total
        epoch_acc = 100.0 * correct / total
        return epoch_loss, epoch_acc

    def save_checkpoint(
        self,
        epoch: int,
        optimizer: optim.Optimizer,
        scheduler: Any,
        val_loss: float,
        val_acc: float,
        is_best: bool = False,
    ):
        """Save a training checkpoint."""
        checkpoint = {
            "epoch": epoch,
            "architecture": self.architecture,
            "model_state_dict": self.model.state_dict(),
            "optimizer_state_dict": optimizer.state_dict(),
            "scheduler_state_dict": scheduler.state_dict(),
            "val_loss": val_loss,
            "val_acc": val_acc,
            "training_history": self.training_history,
            "config": {
                "learning_rate": self.config.learning_rate,
                "batch_size": self.config.batch_size,
                "num_epochs": self.config.num_epochs,
            },
        }

        filepath = os.path.join(
            self.config.checkpoint_dir,
            f"{self.architecture}_epoch_{epoch}.pth"
        )
        torch.save(checkpoint, filepath)

        if is_best:
            best_path = os.path.join(
                self.config.checkpoint_dir,
                f"{self.architecture}_best.pth"
            )
            torch.save(checkpoint, best_path)
            logger.info(f"Saved best model: val_acc={val_acc:.2f}%")

    def load_training_checkpoint(
        self,
        checkpoint_path: str,
        optimizer: Optional[optim.Optimizer] = None,
        scheduler: Optional[Any] = None,
    ) -> int:
        """Resume training from a checkpoint."""
        checkpoint = torch.load(
            checkpoint_path,
            map_location=self.device,
            weights_only=False
        )

        self.model.load_state_dict(checkpoint["model_state_dict"])

        if optimizer and "optimizer_state_dict" in checkpoint:
            optimizer.load_state_dict(checkpoint["optimizer_state_dict"])

        if scheduler and "scheduler_state_dict" in checkpoint:
            scheduler.load_state_dict(checkpoint["scheduler_state_dict"])

        if "training_history" in checkpoint:
            self.training_history = checkpoint["training_history"]

        epoch = checkpoint.get("epoch", 0)
        logger.info(f"Resumed training from epoch {epoch}")
        return epoch

    def fine_tune(
        self,
        train_dataset: Dataset,
        val_dataset: Optional[Dataset] = None,
        resume_from: Optional[str] = None,
    ) -> Dict[str, List[float]]:
        """Main fine-tuning loop."""
        # Split dataset if no validation set provided
        if val_dataset is None:
            val_size = int(len(train_dataset) * self.config.validation_split)
            train_size = len(train_dataset) - val_size
            train_dataset, val_dataset = random_split(
                train_dataset, [train_size, val_size]
            )
            logger.info(
                f"Split dataset: {train_size} train, {val_size} validation"
            )

        train_loader = DataLoader(
            train_dataset,
            batch_size=self.config.batch_size,
            shuffle=True,
            num_workers=self.config.num_workers,
            pin_memory=True if self.device.type == "cuda" else False,
        )

        val_loader = DataLoader(
            val_dataset,
            batch_size=self.config.batch_size,
            shuffle=False,
            num_workers=self.config.num_workers,
            pin_memory=True if self.device.type == "cuda" else False,
        )

        # Freeze backbone if configured
        if self.config.freeze_layers:
            self.freeze_backbone(self.config.unfreeze_last_n)

        criterion = nn.CrossEntropyLoss()
        optimizer, scheduler = self.get_optimizer_and_scheduler()

        start_epoch = 0
        if resume_from:
            start_epoch = self.load_training_checkpoint(
                resume_from, optimizer, scheduler
            )

        patience_counter = 0

        logger.info(
            f"Starting fine-tuning on {self.device} "
            f"for {self.config.num_epochs} epochs"
        )
        logger.info(f"Architecture: {self.architecture}")

        for epoch in range(start_epoch, self.config.num_epochs):
            logger.info(f"\nEpoch [{epoch + 1}/{self.config.num_epochs}]")

            # Train
            train_loss, train_acc = self.train_epoch(
                train_loader, criterion, optimizer
            )

            # Validate
            val_loss, val_acc = self.validate(val_loader, criterion)

            # Step scheduler
            scheduler.step()

            # Record history
            current_lr = optimizer.param_groups[0]["lr"]
            self.training_history["train_loss"].append(train_loss)
            self.training_history["train_acc"].append(train_acc)
            self.training_history["val_loss"].append(val_loss)
            self.training_history["val_acc"].append(val_acc)
            self.training_history["lr"].append(current_lr)

            logger.info(
                f"  Train Loss: {train_loss:.4f} | Train Acc: {train_acc:.2f}%"
            )
            logger.info(
                f"  Val Loss: {val_loss:.4f} | Val Acc: {val_acc:.2f}%"
            )
            logger.info(f"  Learning Rate: {current_lr:.6f}")

            # Save checkpoint
            is_best = val_acc > self.best_val_acc
            if is_best:
                self.best_val_acc = val_acc
                self.best_val_loss = val_loss
                patience_counter = 0
            else:
                patience_counter += 1

            self.save_checkpoint(
                epoch + 1, optimizer, scheduler,
                val_loss, val_acc, is_best
            )

            # Early stopping
            if patience_counter >= self.config.early_stopping_patience:
                logger.info(
                    f"Early stopping triggered after {epoch + 1} epochs"
                )
                break

        logger.info(
            f"\nFine-tuning complete. "
            f"Best Val Acc: {self.best_val_acc:.2f}%"
        )

        return self.training_history


# ============================================================
# Transfer Learning Pipeline
# ============================================================

class TransferLearningPipeline:
    """End-to-end transfer learning pipeline."""

    def __init__(
        self,
        model_name: str = "resnet50",
        num_classes: int = 10,
        training_config: Optional[TrainingConfig] = None,
        cache_dir: str = "./model_cache",
    ):
        self.model_name = model_name
        self.num_classes = num_classes
        self.training_config = training_config or TrainingConfig()
        self.downloader = ModelDownloader(cache_dir=cache_dir)
        self.loader = ModelLoader()

        if model_name in MODEL_REGISTRY:
            self.model_config = MODEL_REGISTRY[model_name]
        else:
            self.model_config = ModelConfig(
                name=model_name,
                architecture=model_name,
                num_classes=1000,
            )

    def prepare_model(
        self,
        use_torchvision: bool = True,
        custom_checkpoint_url: Optional[str] = None,
    ) -> nn.Module:
        """Download and prepare the pretrained model."""
        architecture = self.model_config.architecture

        if custom_checkpoint_url:
            checkpoint_path = self.downloader.download_checkpoint(
                self.model_name, url=custom_checkpoint_url
            )
            model = self.loader.load_checkpoint(
                str(checkpoint_path), architecture
            )
        elif use_torchvision:
            model = self.loader.load_from_torchvision(
                architecture, pretrained=True
            )
        else:
            checkpoint_path = self.downloader.download_checkpoint(
                self.model_name
            )
            model = self.loader.load_checkpoint(
                str(checkpoint_path), architecture
            )

        # Adapt classifier for new number of classes
        model = self.loader.adapt_classifier(
            model, architecture, self.num_classes
        )

        return model

    def prepare_data(
        self,
        train_dir: Optional[str] = None,
        val_dir: Optional[str] = None,
        use_synthetic: bool = False,
        synthetic_samples: int = 500,
    ) -> Tuple[Dataset, Optional[Dataset]]:
        """Prepare training and validation datasets."""
        input_size = self.model_config.input_size

        if use_synthetic:
            logger.info("Using synthetic dataset for demonstration")
            train_dataset = SyntheticDataset(
                num_samples=synthetic_samples,
                num_classes=self.num_classes,
                image_size=input_size,
            )
            val_dataset = SyntheticDataset(
                num_samples=synthetic_samples // 5,
                num_classes=self.num_classes,
                image_size=input_size,
            )
            return train_dataset, val_dataset

        train_transform = get_transforms(input_size, is_training=True)
        val_transform = get_transforms(input_size, is_training=False)

        if train_dir and Path(train_dir).exists():
            train_dataset = torchvision.datasets.ImageFolder(
                train_dir, transform=train_transform
            )
        else:
            train_dataset = CustomImageDataset(
                train_dir or "./data/train", transform=train_transform
            )

        val_dataset = None
        if val_dir and Path(val_dir).exists():
            val_dataset = torchvision.datasets.ImageFolder(
                val_dir, transform=val_transform
            )
        elif val_dir:
            val_dataset = CustomImageDataset(
                val_dir, transform=val_transform
            )

        return train_dataset, val_dataset

    def run(
        self,
        train_dir: Optional[str] = None,
        val_dir: Optional[str] = None,
        use_synthetic: bool = False,
        use_torchvision: bool = True,
        custom_checkpoint_url: Optional[str] = None,
        resume_from: Optional[str] = None,
    ) -> Dict[str, Any]:
        """Run the complete transfer learning pipeline."""
        logger.info("=" * 60)
        logger.info("Transfer Learning Pipeline")
        logger.info("=" * 60)

        # Step 1: Prepare model
        logger.info("\n[Step 1] Preparing pretrained model...")
        model = self.prepare_model(use_torchvision, custom_checkpoint_url)

        # Step 2: Prepare data
        logger.info("\n[Step 2] Preparing datasets...")
        train_dataset, val_dataset = self.prepare_data(
            train_dir, val_dir, use_synthetic
        )

        # Step 3: Fine-tune
        logger.info("\n[Step 3] Fine-tuning model...")
        fine_tuner = FineTuner(
            model, self.training_config, self.model_config.architecture
        )
        history = fine_tuner.fine_tune(
            train_dataset, val_dataset, resume_from
        )

        results = {
            "model_name": self.model_name,
            "architecture": self.model_config.architecture,
            "num_classes": self.num_classes,
            "best_val_acc": fine_tuner.best_val_acc,
            "best_val_loss": fine_tuner.best_val_loss,
            "training_history": history,
            "checkpoint_dir": self.training_config.checkpoint_dir,
        }

        logger.info("\n" + "=" * 60)
        logger.info("Pipeline Complete!")
        logger.info(f"Best Validation Accuracy: {results['best_val_acc']:.2f}%")
        logger.info(
            f"Checkpoints saved to: {results['checkpoint_dir']}"
        )
        logger.info("=" * 60)

        return results


# ============================================================
# Utility Functions
# ============================================================

def list_available_models() -> List[str]:
    """List all available pretrained models in the registry."""
    return list(MODEL_REGISTRY.keys())


def export_model_onnx(
    model: nn.Module,
    output_path: str,
    input_size: Tuple[int, ...] = (1, 3, 224, 224),
    device: str = "cpu",
):
    """Export a fine-tuned model to ONNX format."""
    model.eval()
    model = model.to(device)
    dummy_input = torch.randn(*input_size).to(device)

    torch.onnx.export(
        model,
        dummy_input,
        output_path,
        export_params=True,
        opset_version=11,
        do_constant_folding=True,
        input_names=["input"],
        output_names=["output"],
        dynamic_axes={
            "input": {0: "batch_size"},
            "output": {0: "batch_size"},
        },
    )
    logger.info(f"Model exported to ONNX: {output_path}")


